# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.examples.run_all_examples","kind":"function","src_hash":"1e79db1318c7ca7d","in":{"base":"bool"},"out":{"base":"bool"},"spec":{"lhs":"run_all_examples(ver)","rhs":"run and verify all proof examples","over":{"base":"bool"},"name":"run_all_examples_correct"},"guarantee":"run and verify all proof examples","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.examples.run_all_examples_correct","statement":"Path(run_all_examples(x), run and verify all proof examples)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"f65df492f6158c33"}
def run_all_examples(verbose: bool = True) -> bool:
    """Run and verify all proof examples.

    Returns True iff all proofs check.
    """
    all_ok = True
    results = []

    for name, lhs, rhs, proof in ALL_EXAMPLES:
        result = check_proof(proof, lhs, rhs)
        status = '✓ VERIFIED' if result.valid else '✗ REJECTED'
        results.append((name, result))

        if verbose:
            print(f'  {status:12s}  {name:40s}  '
                  f'({result.time_ms:.1f}ms, depth={result.proof_depth})'
                  f'{"" if result.valid else "  reason=" + result.reason}')

        if not result.valid:
            all_ok = False

    if verbose:
        verified = sum(1 for _, r in results if r.valid)
        total = len(results)
        print(f'\n  {verified}/{total} proofs verified')

    return all_ok


